```rust
// In src/main.rs
use crate::output::{Output, OutputFormat, Verbosity};

fn main() -> Result<()> {
    let args = Args::parse();

    // Initialize output with format and verbosity from args
    let verbosity = Verbosity::from_flags(args.quiet, args.verbose);
    let output = Output::new(args.format)
        .with_verbosity(verbosity)
        .with_theme_name(args.theme.as_deref());

    // Initialize tracing for debug output
    if verbosity >= Verbosity::Debug {
        output.init_tracing();
    }

    // Run command with output context
    let result = match args.command {
        Command::Search(search_args) => run_search(search_args, &output),
        Command::Stats => run_stats(&output),
        Command::Index(index_args) => run_index(index_args, &output),
        Command::Doctor => run_doctor(&output),
        Command::Repl => run_repl(&output),
        Command::ListHashtags(args) => run_list_hashtags(args, &output),
        Command::ListMentions(args) => run_list_mentions(args, &output),
        Command::Completions(shell) => generate_completions(shell, &output),
        Command::Help => render_help(&output),
    };

    // Handle errors with styled output
    if let Err(err) = result {
        handle_error(err, &output);
        std::process::exit(1);
    }

    Ok(())
}
