// In src/output/mod.rs
// Provide a fallback when rich feature is not enabled

#[cfg(feature = "rich")]
mod rich_impl {
    pub use rich_rust::prelude::*;
    // Full rich implementation
}

#[cfg(not(feature = "rich"))]
mod plain_impl {
    //! Fallback implementation when rich feature is disabled
    //! Provides the same API but with plain text output

    pub struct Console;

    impl Console {
        pub fn new() -> Self { Self }
        pub fn print(&self, text: &str) { println!("{}", text); }
        pub fn rule(&self, title: Option<&str>) {
            if let Some(t) = title {
                println!("--- {} ---", t);
            } else {
                println!("---");
            }
        }
    }

    pub struct Panel {
        content: String,
        title: Option<String>,
    }

    impl Panel {
        pub fn from_text(text: &str) -> Self {
            Self { content: text.to_string(), title: None }
        }
        pub fn title(mut self, title: &str) -> Self {
            self.title = Some(title.to_string());
            self
        }
        pub fn border_style(self, _: impl Into<Color>) -> Self { self }
    }

    pub struct Table {
        title: Option<String>,
        columns: Vec<Column>,
        rows: Vec<Vec<String>>,
    }

    impl Table {
        pub fn new() -> Self {
            Self { title: None, columns: vec![], rows: vec![] }
        }
        pub fn title(mut self, title: &str) -> Self {
            self.title = Some(title.to_string());
            self
        }
        pub fn with_column(mut self, col: Column) -> Self {
            self.columns.push(col);
            self
        }
        pub fn add_row_cells(&mut self, cells: impl IntoIterator<Item = impl AsRef<str>>) {
            self.rows.push(cells.into_iter().map(|s| s.as_ref().to_string()).collect());
        }
    }

    pub struct Column {
        name: String,
        width: Option<usize>,
        justify: JustifyMethod,
    }

    impl Column {
        pub fn new(name: &str) -> Self {
            Self { name: name.to_string(), width: None, justify: JustifyMethod::Left }
        }
        pub fn width(mut self, w: usize) -> Self { self.width = Some(w); self }
        pub fn justify(mut self, j: JustifyMethod) -> Self { self.justify = j; self }
        pub fn style(self, _: Style) -> Self { self }
    }

    #[derive(Clone, Copy)]
    pub enum JustifyMethod { Left, Right, Center }

    #[derive(Clone, Copy)]
