use crate::output::{Output, doctor::{DoctorReport, HealthStatus}};

pub fn run_doctor(output: &Output) -> Result<()> {
    output.print_verbose("Running diagnostic checks...");

    let config = load_config()?;
    let report = DoctorReport::run_all_checks(&config);
    report.render(output);

    // Exit code based on health
    match report.overall_status {
        HealthStatus::Error => std::process::exit(1),
        HealthStatus::Warning => std::process::exit(0), // Warnings are not failures
        _ => std::process::exit(0),
    }
}
