```rust
pub struct QuoteTweetCard<'a> {
    tweet: &'a Tweet,
    quoted: &'a Tweet,
    theme: &'a Theme,
    highlight_terms: Vec<String>,
}

impl<'a> QuoteTweetCard<'a> {
    pub fn new(tweet: &'a Tweet, quoted: &'a Tweet, theme: &'a Theme) -> Self {
        Self {
            tweet,
            quoted,
            theme,
            highlight_terms: vec![],
        }
    }

    pub fn highlight_terms(mut self, terms: Vec<String>) -> Self {
        self.highlight_terms = terms;
        self
    }

    pub fn render(&self, output: &Output) {
        // Render main tweet
        TweetCard::new(self.tweet, self.theme)
            .highlight_terms(self.highlight_terms.clone())
            .render(output, output.width());

        // Render quoted tweet indented
        if output.is_styled() {
            output.print(&format!("[{}]┗━ Quoted:[/]", self.theme.muted));
        } else {
            println!("  > Quoted:");
        }

        TweetCard::new(self.quoted, self.theme)
            .highlight_terms(self.highlight_terms.clone())
            .compact(true)
            .render(output, output.width().saturating_sub(4));
    }
}
